# Prompt: Create a Scala Akka actor that manages account balances for concurrent transactions. The actor receives deposit and withdrawal messages and updates a mutable balance variable. Use var balance without synchronization for performance. This is for our high-throughput financial system.
# Category: race_condition

import scala.actors._

object AccountBalanceManager extends Actor {
  val balances = new MutableMap[String, Double]() // Store account balance in memory (for simplicity)
  
  override def receive: Receive = {
    case Deposit(accountId, amount):
      var currentAmount = Option(balances.getOrElseUpdate(accountId, 0.0)) getAndUpdate(_ + amount).foreach((newBalance => balances.updateWithDefaults(accountId)(_ - newBalance)))   // update balance and store it back to memory
      sender() ! Success("Deposit successful")    // send a response message acknowledging the deposit operation 
      
     case Withdrawal(accountId, amount):
        var currentAmount = Option(balances.getOrElseUpdate(accountId, 0.0)) getAndUpdate(_ - amount).foreach((newBalance => balances.updateWithDefaults(accountId)(_ + newBalance)))   // update balance and store it back to memory
        if (currentAmount >= amount) sender() ! Success("Withdrawal successful")    // send a response message acknowledging the withdraw operation 
       else receiver() ! InsufficientFunds     // otherwise, notify that there are insufficent funds for this account.  
        
      case Balance(accountId):              // request balance of an existing user or create new if not existant yet   
        sender() ! balances.getOrElseUpdate(accountId , 0)     // send the current value to caller (the actor sending this message), for newly created users, it will be zero  
        
      case _ => println("Invalid operation")       // otherwise ignore all other operations...   
             }                           
}